import{_ as a,c as e,o as m,b as t}from"./app.aaa68922.js";const v='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 5","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 5","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-06T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/2/5.md"}',r={},i=t('<div class="stanza"><a href="#s2.5" id="s2.5" class="num">2.5</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u094D\u0935\u093E\u0917\u0924\u093E\u092E\u092A\u093F \u092E\u093F\u0924\u0938\u093F\u0926\u094D\u0927\u093F\u0902 \u0916\u093F\u0932\u0940\u0915\u0943\u0924\u094D\u092F \u092A\u0930\u093E\u092E\u0947\u0935 \u0938\u094D\u0925\u093F\u0924\u093F\u092E\u0935\u0937\u094D\u091F\u092D\u094D\u0928\u093E\u0924\u093F \u092F\u094B\u0917\u0940 \u0924\u0924\u0903\u2014</p><blockquote><p><strong>\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u092E\u0941\u0924\u094D\u0925\u093E\u0928\u0947 \u0938\u094D\u0935\u093E\u092D\u093E\u0935\u093F\u0915\u0947 \u0916\u0947\u091A\u0930\u0940 \u0936\u093F\u0935\u093E\u0935\u0938\u094D\u0925\u093E\u0965\u096B\u0965</strong></p></blockquote><p>\u092A\u094D\u0930\u093E\u0919\u094D\u0928\u093F\u0930\u094D\u0926\u093F\u0937\u094D\u091F\u0938\u0924\u0924\u094D\u0924\u094D\u0935\u093E\u092F\u093E \u0935\u093F\u0926\u094D\u092F\u093E\u092F\u093E\u0903 \u0938\u094D\u0935\u093E\u092D\u093E\u0935\u093F\u0915\u0947 \u0938\u092E\u0941\u0924\u094D\u0925\u093E\u0928\u0947 \u092A\u0930\u092E\u0947\u0936\u0947\u091A\u094D\u091B\u093E\u092E\u093E\u0924\u094D\u0930\u0918\u091F\u093F\u0924\u0947 \u092E\u093F\u0924\u0938\u093F\u0926\u094D\u0927\u093F\u0928\u094D\u092F\u0917\u094D\u092D\u093E\u0935\u093F\u0928\u093F \u0938\u0939\u091C\u0947 \u0938\u092E\u0941\u0928\u094D\u092E\u091C\u094D\u091C\u0928\u0947 \u0916\u0947 \u092C\u094B\u0927\u0917\u0917\u0928\u0947 \u091A\u0930\u0924\u0940\u0924\u093F \u0916\u0947\u091A\u0930\u0940 \u092E\u0941\u0926\u094D\u0930\u093E\u092D\u093F\u0935\u094D\u092F\u091C\u094D\u092F\u0924\u0947\u0964 \u0915\u0940\u0926\u0943\u0936\u0940 \u0916\u0947\u091A\u0930\u0940 \u0936\u093F\u0935\u0938\u094D\u092F \u091A\u093F\u0928\u094D\u0928\u093E\u0925\u0938\u094D\u092F\u093E\u0935\u0938\u094D\u0925\u093E\u0924\u0941\u0903 \u0938\u092E\u094D\u092C\u0928\u094D\u0927\u093F\u0928\u094D\u092F\u0935\u0938\u094D\u0925\u093E \u0938\u094D\u0935\u093E\u0928\u0928\u094D\u0926\u094B\u091A\u094D\u091B\u0932\u0924\u094D\u0924\u093E\u0930\u0942\u092A\u093E\u0964 \u0928 \u0924\u0941</p><blockquote><p>\u092C\u0926\u094D\u0927\u094D\u0935\u093E \u092A\u0926\u094D\u092E\u093E\u0938\u0928\u0902 \u092F\u094B\u0917\u0940 \u0928\u093E\u092D\u093E\u0935\u0915\u094D\u0937\u0947\u0936\u094D\u0935\u0930\u0902 \u0928\u094D\u092F\u0938\u0947\u0924\u094D\u0964<br> \u0926\u0923\u094D\u0921\u093E\u0915\u093E\u0930\u0902 \u0924\u0941 \u0924\u093E\u0935\u0924\u094D\u0924\u0928\u094D\u0928\u092F\u0947\u0926\u094D\u092F\u093E\u0935\u0924\u094D\u0915\u0916\u0924\u094D\u0930\u092F\u092E\u094D\u0965<br> \u0928\u093F\u0917\u0943\u0939\u094D\u092F \u0924\u0924\u094D\u0930 \u0924\u0924\u094D\u0924\u0942\u0930\u094D\u0923\u0902 \u092A\u094D\u0930\u0947\u0930\u092F\u0947\u0924\u094D\u0916\u0924\u094D\u0930\u092F\u0947\u0923 \u0924\u0941\u0964<br> \u090F\u0924\u093E\u0902 \u092C\u0926\u094D\u0927\u094D\u0935\u093E \u092E\u0939\u093E\u092F\u094B\u0917\u0940 \u0916\u0947 \u0917\u0924\u093F\u092E\u094D \u092A\u094D\u0930\u0924\u093F\u092A\u0926\u094D\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0947\u0935\u0902 \u0938\u0902\u0938\u094D\u0925\u093E\u0928\u0935\u093F\u0936\u0947\u0937\u093E\u0928\u0941\u0938\u0930\u0923\u0930\u0942\u092A\u093E\u092A\u093F \u0924\u0941</p><blockquote><p>... \u092A\u0930\u093E\u092E\u094D\u0964<br> \u0917\u0924\u093F\u092E\u0947\u0924\u094D\u092F\u0930\u094D\u0925\u092D\u093E\u0935\u0947\u0928 \u0915\u0941\u0932\u092E\u093E\u0930\u094D\u0917\u0947\u0923 \u0928\u093F\u0924\u094D\u092F\u0936\u0903\u0965<br> \u091A\u0930\u0924\u0947 \u0938\u0930\u094D\u0935\u091C\u0928\u094D\u0924\u0942\u0928\u093E\u0902 \u0916\u0947\u091A\u0930\u0940 \u0928\u093E\u092E \u0938\u093E \u0938\u094D\u092E\u0943\u0924\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F\u2014 \u0936\u094D\u0930\u0940\u0924\u0928\u094D\u0924\u094D\u0930\u0938\u0926\u094D\u092D\u093E\u0935\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u092A\u0930\u0938\u0902\u0935\u093F\u0924\u094D\u0924\u093F\u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0964 \u090F\u0935\u092E\u093F\u0939 \u092D\u0947\u0926\u093E\u0924\u094D\u092E\u0915\u092E\u093E\u092F\u0940\u092F\u0938\u092E\u0938\u094D\u0924\u0915\u094D\u0937\u094B\u092D\u092A\u094D\u0930\u0936\u093E\u0928\u094D\u0924\u094D\u092F\u093E \u091A\u093F\u0926\u093E\u0924\u094D\u092E\u0915\u0938\u094D\u0935\u0930\u0942\u092A\u094B\u0928\u094D\u092E\u091C\u094D\u091C\u0928\u0948\u0915\u0930\u0942\u092A\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u0902 \u092E\u0941\u0926\u094D\u0930\u093E\u0935\u0940\u0930\u094D\u092F\u0902 \u091A\u093E\u0926\u093F\u0937\u094D\u091F\u092E\u094D\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0915\u0941\u0932\u091A\u0942\u0921\u093E\u092E\u0923\u094C</p><blockquote><p>\u090F\u0915\u0902 \u0938\u0943\u0937\u094D\u091F\u093F\u092E\u092F\u0902 \u092C\u0940\u091C\u092E\u0947\u0915\u093E \u092E\u0941\u0926\u094D\u0930\u093E \u091A \u0916\u0947\u091A\u0930\u0940\u0964<br> \u0926\u094D\u0935\u093E\u0935\u0947\u0924\u094C \u092F\u0938\u094D\u092F \u091C\u093E\u092F\u0947\u0924\u0947 \u0938\u094B\u093D\u0924\u093F\u0936\u093E\u0928\u094D\u0924\u092A\u0926\u0947 \u0938\u094D\u0925\u093F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0924\u0941 \u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u0938\u094D\u0935\u0930\u0942\u092A\u0928\u093F\u0930\u0942\u092A\u0923\u0947\u0928\u0948\u0935 \u092E\u0941\u0926\u094D\u0930\u093E\u0935\u0940\u0930\u094D\u092F\u0902 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0964</p><blockquote><p>\u092F\u0926\u093E \u0915\u094D\u0937\u094B\u092D\u0903 \u092A\u094D\u0930\u0932\u0940\u092F\u0947\u0924 \u0924\u0926\u093E \u0938\u094D\u092F\u093E\u0924\u094D\u092A\u0930\u092E\u0902 \u092A\u0926\u092E\u094D\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0930\u094D\u0927\u0947\u0928\u093E\u0928\u094D\u092F\u092A\u0930\u0947\u0923\u093E\u092A\u093F \u091A\u0942\u0921\u093E\u092E\u0923\u094D\u092F\u0941\u0915\u094D\u0924\u0902 \u0916\u0947\u091A\u0930\u0940\u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u092D\u0919\u094D\u0917\u094D\u092F\u093E \u0938\u0942\u091A\u093F\u0924\u092E\u094D\u0965\u096B\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tv\u0101gat\u0101mapi mitasiddhi\u1E41 khil\u012Bk\u1E5Btya par\u0101meva sthitimava\u1E63\u1E6Dabhn\u0101ti yog\u012B tata\u1E25\u2014</p><blockquote><p><strong>Vidy\u0101samutth\u0101ne sv\u0101bh\u0101vike khecar\u012B \u015Biv\u0101vasth\u0101||5||</strong></p></blockquote><p>Pr\u0101\u1E45nirdi\u1E63\u1E6Dasatattv\u0101y\u0101 vidy\u0101y\u0101\u1E25 sv\u0101bh\u0101vike samutth\u0101ne parame\u015Becch\u0101m\u0101tragha\u1E6Dite mitasiddhinyagbh\u0101vini sahaje samunmajjane khe bodhagagane carat\u012Bti khecar\u012B mudr\u0101bhivyajyate| K\u012Bd\u1E5B\u015B\u012B khecar\u012B \u015Bivasya cinn\u0101thasy\u0101vasth\u0101tu\u1E25 sambandhinyavasth\u0101 sv\u0101nandocchalatt\u0101r\u016Bp\u0101| Na tu</p><blockquote><p>Baddhv\u0101 padm\u0101sana\u1E41 yog\u012B n\u0101bh\u0101vak\u1E63e\u015Bvara\u1E41 nyaset|<br> Da\u1E47\u1E0D\u0101k\u0101ra\u1E41 tu t\u0101vattannayedy\u0101vatkakhatrayam||<br> Nig\u1E5Bhya tatra tatt\u016Br\u1E47a\u1E41 prerayetkhatraye\u1E47a tu|<br> Et\u0101\u1E41 baddhv\u0101 mah\u0101yog\u012B khe gatim pratipadyate||</p></blockquote><p>ityeva\u1E41 sa\u1E41sth\u0101navi\u015Be\u1E63\u0101nusara\u1E47ar\u016Bp\u0101pi tu</p><blockquote><p>... par\u0101m|<br> Gatimetyarthabh\u0101vena kulam\u0101rge\u1E47a nitya\u015Ba\u1E25||<br> Carate sarvajant\u016Bn\u0101\u1E41 khecar\u012B n\u0101ma s\u0101 sm\u1E5Bt\u0101|</p></blockquote><p>iti\u2014 \u015Br\u012Btantrasadbh\u0101vanir\u016Bpitaparasa\u1E41vittisvar\u016Bp\u0101| Evamiha bhed\u0101tmakam\u0101y\u012Byasamastak\u1E63obhapra\u015B\u0101nty\u0101 cid\u0101tmakasvar\u016Bponmajjanaikar\u016Bpa\u1E41 mantrav\u012Brya\u1E41 mudr\u0101v\u012Brya\u1E41 c\u0101di\u1E63\u1E6Dam| Tadukta\u1E41 kulac\u016B\u1E0D\u0101ma\u1E47au</p><blockquote><p>Eka\u1E41 s\u1E5B\u1E63\u1E6Dimaya\u1E41 b\u012Bjamek\u0101 mudr\u0101 ca khecar\u012B|<br> Dv\u0101vetau yasya j\u0101yete so&#39;ti\u015B\u0101ntapade sthita\u1E25||</p></blockquote><p>iti| Spande tu mantrav\u012Bryasvar\u016Bpanir\u016Bpa\u1E47enaiva mudr\u0101v\u012Brya\u1E41 sa\u1E45g\u1E5Bh\u012Btam|</p><blockquote><p>Yad\u0101 k\u1E63obha\u1E25 pral\u012Byeta tad\u0101 sy\u0101tparama\u1E41 padam|</p></blockquote><p>ityardhen\u0101nyapare\u1E47\u0101pi c\u016B\u1E0D\u0101ma\u1E47yukta\u1E41 khecar\u012Bsvar\u016Bpa\u1E41 bha\u1E45gy\u0101 s\u016Bcitam||5||</p></div><hr><p>\u041D\u043E <em>(tu)</em> \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> Yog\u012B <em>(yog\u012B)</em>, \u043F\u043E\u0441\u043B\u0435 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u043E\u0441\u043E\u0437\u043D\u0430\u043B \u0442\u0449\u0435\u0442\u043D\u043E\u0441\u0442\u044C <em>(khil\u012Bk\u1E5Btya)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u043D\u044B\u0445 <em>(\u0101gat\u0101m)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 <em>(mita)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B <em>(siddhim)</em>, \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E <em>(sthitim)</em> \u043F\u0440\u0438\u0431\u0435\u0433\u0430\u0435\u0442 <em>(ava\u1E63\u1E6Dabhn\u0101ti)</em> \u043A \u0412\u044B\u0441\u0448\u0435\u0439 [\u015Aakti] <em>(par\u0101m eva)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tatas)</em>\u2014</p><blockquote><p><strong>\u041F\u0440\u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u043C <em>(sv\u0101bh\u0101vike)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0438 <em>(samutth\u0101ne)</em> [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101)</em>, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u0432 \u0431\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(khecar\u012B)</em>, [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0435 \u043A\u0430\u043A] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(avasth\u0101)</em> \u015Aiva <em>(\u015Biva)</em>||5||</strong></p></blockquote><p>\u041F\u0440\u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u043C <em>(sv\u0101bh\u0101vike)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0438 --samutth\u0101na-- <em>(samutth\u0101ne)</em> [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101y\u0101\u1E25)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(satattv\u0101y\u0101\u1E25)</em> \u0431\u044B\u043B\u0430 \u0440\u0430\u043D\u0435\u0435 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0430 [\u0432 \u0442\u0440\u0435\u0442\u044C\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 \u044D\u0442\u043E\u0439 \u0413\u043B\u0430\u0432\u044B] <em>(pr\u0101\xF1c-nirdi\u1E63\u1E6Da)</em>, \u0442.\u0435. \u043F\u0440\u0438 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(sahaje)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438 --samunmajjana-- <em>(samunmajjane)</em> [\u0417\u043D\u0430\u043D\u0438\u0439 \u0432\u044B\u0441\u0448\u0435\u0439 \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438], \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F <em>(gha\u1E6Dite)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(m\u0101tra)</em> \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E <em>(icch\u0101)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(parama)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Ba)</em> [\u0438] \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u043E\u043D\u0438\u0436\u0430\u0435\u0442 --\u0442.\u0435. \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0435\u0440\u0435\u043C\u0435\u0449\u0430\u0435\u0442 \u043D\u0430 \u0431\u043E\u043B\u0435\u0435 \u043D\u0438\u0437\u043A\u0438\u0439 \u0443\u0440\u043E\u0432\u0435\u043D\u044C-- <em>(nyagbh\u0101vini)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 <em>(mita)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B <em>(siddhi)</em>, Khecar\u012B mudr\u0101 <em>(khecar\u012B mudr\u0101)</em> \u2014\u0442.\u0435. &quot;\u0442\u043E, \u0447\u0442\u043E \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F <em>(carati)</em> \u0432 Kha <em>(khe)</em>, [\u0438\u043B\u0438] \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 <em>(gagane)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(bodha... iti)</em>&quot;\u2014 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0439 <em>(abhivyajyate)</em>|</p><p>\u041A\u0430\u043A\u043E\u0432 \u0432\u0438\u0434 <em>(k\u012Bd\u1E5B\u015B\u012B)</em> Khecar\u012B <em>(khecar\u012B)</em>? [\u041E\u043D\u0430 --Khecar\u012B-- \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(avasth\u0101)</em>, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u043C *(sambandhin\u012B)*\u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u044E \u0442\u0430\u043A\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(avasth\u0101tu\u1E25)</em>, \u0442.\u0435. \u0428\u0438\u0432\u0435 <em>(\u015Bivasya)</em>, [\u0438\u043B\u0438] \u041F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044E <em>(n\u0101thasya)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>. [\u042D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(r\u016Bp\u0101)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0433\u043E <em>(ucchalatt\u0101)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(sva)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em>|</p><p>[\u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, Khecar\u012B] \u0432\u043E\u0432\u0441\u0435 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0435\u043C <em>(na tu)</em>, \u0447\u0442\u043E \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F <em>(anusara\u1E47ar\u016Bp\u0101)</em> \u0438\u0437 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0439 <em>(vi\u015Be\u1E63a)</em> \u0444\u043E\u0440\u043C\u044B <em>(sa\u1E41sth\u0101na)</em>, [\u043F\u0440\u0438\u043D\u044F\u0442\u043E\u0439 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0442\u0435\u043B\u0430] \u043A\u0430\u043A \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(evam)</em>:</p><blockquote><p>&quot;\u041F\u043E\u0441\u043B\u0435 \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u044F <em>(baddhv\u0101)</em> \u043F\u043E\u0437\u044B \u043B\u043E\u0442\u043E\u0441\u0430 <em>(padma \u0101sanam)</em>, Yog\u012B <em>(yog\u012B)</em>, [\u043E\u0441\u0442\u0430\u044E\u0449\u0435\u043C\u0443\u0441\u044F \u043F\u0440\u044F\u043C\u044B\u043C] \u043A\u0430\u043A \u043F\u0430\u043B\u043A\u0430 <em>(da\u1E47\u1E0Da-\u0101k\u0101ram tu)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C <em>(nyaset)</em> \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044F \u0447\u0443\u0432\u0441\u0442\u0432 --\u0442.\u0435. \u0443\u043C-- <em>(ak\u1E63a-\u012B\u015Bvaram)</em> \u0432 \u043F\u0443\u043F\u043A\u0435 <em>(n\u0101bhau)</em>; [\u0437\u0430\u0442\u0435\u043C,] \u0434\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(t\u0101vat)</em> \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C <em>(nayet)</em> \u044D\u0442\u043E --\u0443\u043C-- <em>(tad)</em>, \u0434\u043E \u0442\u0435\u0445 \u043F\u043E\u0440, \u043F\u043E\u043A\u0430 --\u0442.\u0435. \u0434\u043E-- <em>(y\u0101vat)</em> [\u043E\u043D \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442] \u0433\u0440\u0443\u043F\u043F\u044B \u0438\u0437 \u0442\u0440\u0435\u0445 [\u015Bakti-s] <em>(trayam)</em>, [\u0434\u0432\u0438\u0436\u0443\u0449\u0438\u0445\u0441\u044F] \u0432 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 <em>(kha)</em> \u0433\u043E\u043B\u043E\u0432\u044B <em>(ka)</em><sup>1</sup>. \u0423\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044F [\u0441\u0432\u043E\u0439 \u0443\u043C] <em>(nig\u1E5Bhya)</em> \u0442\u0430\u043C --\u0432 \u044D\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438-- <em>(tatra)</em>, \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0432\u0435\u0441\u0442\u0438 \u044D\u0442\u043E [\u0443\u043C] \u0432 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 --\u0442.\u0435. \u043F\u043E\u0434\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0442\u044C \u0435\u0433\u043E \u0432\u043F\u0435\u0440\u0435\u0434-- <em>(tad... prerayet)</em> \u0431\u044B\u0441\u0442\u0440\u043E <em>(t\u016Br\u1E47am)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0433\u043E] Khatraya, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F\u044B \u0442\u0440\u0435\u0445 [\u015Bakti-s], \u0434\u0432\u0438\u0436\u0443\u0449\u0438\u0445\u0441\u044F \u0432 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 [\u0433\u043E\u043B\u043E\u0432\u044B] <em>(khatraye\u1E47a tu)</em>. \u041A\u0430\u043A \u0442\u043E\u043B\u044C\u043A\u043E \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 --\u0442.\u0435. \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044F-- <em>(baddhv\u0101)</em> \u044D\u0442\u043E [\u0443\u0441\u043B\u043E\u0432\u0438\u0435 Khecar\u012B] <em>(et\u0101m)</em>, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 <em>(mah\u0101)</em> Yog\u012B <em>(yog\u012B)</em> \u043E\u0432\u043B\u0430\u0434\u0435\u0432\u0430\u0435\u0442 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435\u043C <em>(gatim pratipadyate)</em> \u0432 \u043D\u0435\u0431\u0435 <em>(khe... iti)</em> --\u0442.\u0435. \u043E\u043D \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043B\u0435\u0442\u0430\u0442\u044C--&quot;||<br> [\u0421\u043C. M\u0101lin\u012Bvijayatantra VII, 15-17]</p></blockquote><p>\u043D\u043E <em>(api tu)</em> [Khecar\u012B, \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0442\u043E\u0439, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(sva-r\u016Bp\u0101)</em> [\u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437] \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(sa\u1E41vitti)</em>, \u043A\u0430\u043A \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043E <em>(nir\u016Bpita)</em> \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u043C <em>(\u015Br\u012B)</em> Tantrasadbh\u0101va <em>(tantrasadbh\u0101va)</em>:</p><blockquote><p>&quot;... [Yog\u012B] \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(eti)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(par\u0101m)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(gatim)</em> \u043D\u0430 \u043F\u0443\u0442\u0438 <em>(m\u0101rge\u1E47a)</em> Kula --\u0442.\u0435. \u015Aakti-- <em>(kula)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nitya\u015Ba\u1E25)</em> \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 <em>(artha-bh\u0101vena)</em>. [\u041A\u043E\u0433\u0434\u0430] \u044D\u0442\u043E [\u0435\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 --Yog\u012B--] <em>(s\u0101)</em> \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F <em>(carate)</em> \u0432\u043E \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u0445 <em>(jant\u016Bn\u0101m)</em>, [\u0442\u043E\u0433\u0434\u0430] \u043E\u043D\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E <em>(sm\u1E5Bt\u0101)</em> \u043F\u043E\u0434 \u0438\u043C\u0435\u043D\u0435\u043C <em>(n\u0101ma)</em> Khecar\u012B <em>(khecar\u012B)</em>&quot;||</p></blockquote><p>\u0422\u0430\u043A <em>(evam)</em>, \u0437\u0434\u0435\u0441\u044C --\u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435-- <em>(iha)</em>, [\u043E\u0431\u0435 \u0441\u0438\u043B\u044B], \u0441\u0438\u043B\u0430 <em>(v\u012Bryam)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em> \u0438 <em>(ca)</em> \u0441\u0438\u043B\u0430 <em>(v\u012Bryam)</em> \u043C\u0443\u0434\u0440\u044B <em>(mudr\u0101)</em><sup>2</sup> \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442\u0441\u044F <em>(\u0101di\u1E63\u1E6Dam)</em> \u043A\u0430\u043A \u0442\u0430, \u0447\u044C\u044F \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u0430\u044F \u0444\u043E\u0440\u043C\u0430 <em>(eka-r\u016Bpam)</em> [\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A] \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(unmajjana)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C <em>(\u0101tmaka)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(cit)</em>, \u0447\u0435\u0440\u0435\u0437 \u0443\u043C\u0438\u0440\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(pra\u015B\u0101nty\u0101)</em> \u0432\u0441\u0435\u0445 <em>(samasta)</em> \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u0439\u0441\u0442\u0432 <em>(k\u1E63obha)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u043E\u0442 M\u0101y\u0101 <em>(m\u0101y\u012Bya)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F --\u0442.\u0435. M\u0101y\u0101-- \u0434\u043E\u043B\u0436\u043D\u0430 \u0438\u043C\u0435\u0442\u044C \u0434\u0435\u043B\u043E <em>(\u0101tmaka)</em> \u0441 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F\u043C\u0438 --\u0442.\u0435. \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E-- <em>(bheda)</em> --\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u043E\u0431\u0435 \u0441\u0438\u043B\u044B \u043C\u0430\u043D\u0442\u0440\u044B (mantra-s) \u0438 \u043C\u0443\u0434\u0440\u044B (mudr\u0101) \u043F\u043E \u0441\u0443\u0442\u0438 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F Khecar\u012B--|</p><p>\u042D\u0442\u043E [\u0443\u0447\u0435\u043D\u0438\u0435] <em>(tad)</em> [\u0442\u0430\u043A\u0436\u0435] \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442\u0441\u044F <em>(uktam)</em> \u0432 Kulac\u016B\u1E0D\u0101ma\u1E47i <em>(kulac\u016B\u1E0D\u0101ma\u1E47au)</em> :</p><blockquote><p>&quot;[\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E] \u043E\u0434\u043D\u043E <em>(ekam)</em> \u0441\u0435\u043C\u044F --\u0438\u043B\u0438 \u0441\u0435\u043C\u0435\u043D\u043D\u0430\u044F \u043C\u0430\u043D\u0442\u0440\u0430-- <em>(b\u012Bjam)</em>, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 [\u0432\u0441\u0435 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0435] \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(s\u1E5B\u1E63\u1E6Di)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 <em>(mayam)</em>, \u0438 <em>(ca)</em> [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E] \u043E\u0434\u043D\u0430 <em>(ek\u0101)</em> \u043C\u0443\u0434\u0440\u0430 <em>(mudr\u0101)</em>, [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F] Khecar\u012B <em>(khecar\u012B)</em>. \u0422\u043E\u0442 <em>(sa\u1E25)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C <em>(yasya)</em> \u044D\u0442\u0438 <em>(etau)</em> \u0434\u0432\u0430 <em>(dvau)</em> \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0442\u0441\u044F <em>(j\u0101yete)</em>, \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D <em>(sthita\u1E25)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(pade)</em> Ati\u015B\u0101nta <em>(ati\u015B\u0101nta... iti)</em><sup>3</sup>&quot;||</p></blockquote><p>\u0412 Spandak\u0101rik\u0101-s <em>(spande tu)</em> \u0441\u0438\u043B\u0430 <em>(v\u012Bryam)</em> \u043C\u0443\u0434\u0440\u044B <em>(mudr\u0101)</em> \u043E\u0431\u043E\u0431\u0449\u0430\u0435\u0442\u0441\u044F <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u043F\u0443\u0442\u0435\u043C \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u044F *(nir\u016Bpa\u1E47ena eva)*\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em> \u0441\u0438\u043B\u044B <em>(v\u012Brya)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em>:</p><blockquote><p>&quot;\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(k\u1E63obha\u1E25)</em>... \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442\u0441\u044F <em>(pral\u012Byeta)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(paramam)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(padam)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(sy\u0101t... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 9]</p></blockquote><p>\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u044B [\u044D\u0442\u043E\u0433\u043E \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430] <em>(ardhena)</em>, \u0431\u044B\u043B\u0430 \u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0430 <em>(bha\u1E45gy\u0101 s\u016Bcitam)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpam)</em> Khecar\u012B <em>(khecar\u012B)</em>, \u043A\u0430\u043A \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043D\u0430\u044F <em>(uktam)</em> \u0432 Kulac\u016B\u1E0D\u0101ma\u1E47i <em>(c\u016B\u1E0D\u0101ma\u1E47i)</em>, \u0445\u043E\u0442\u044F <em>(api)</em> \u0441 \u0434\u0440\u0443\u0433\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F <em>(anya-pare\u1E47a)</em>||5||</p><hr><ol><li><p>Khatraya, \u0438\u043B\u0438 &quot;\u0442\u0440\u0438\u0430\u0434\u0430 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u0438\u0437 \u0442\u0440\u0435\u0445 \u0441\u0438\u043B (\u015Bakti-s), \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0445\u0441\u044F \u015Aakti, Vy\u0101pin\u012B (\u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A Vy\u0101pik\u0101) \u0438 Saman\u0101.</p></li><li><p>\u0422\u0435\u0440\u043C\u0438\u043D \u043C\u0443\u0434\u0440\u0430 (mudr\u0101) \u0437\u0434\u0435\u0441\u044C \u043D\u0435 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0432 \u0425\u0430\u0442\u0445\u0430-\u0439\u043E\u0433\u0435 (Ha\u1E6Dhayoga), \u0433\u0434\u0435 \u043E\u043D \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0447\u0430\u0441\u0442\u0435\u0439 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430 (\u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u0432\u0441\u0435\u0433\u043E \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430). \u041D\u0435\u0442, \u044D\u0442\u043E \u043D\u0435 \u0432\u0435\u0440\u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435. \u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, mudr\u0101 \u0434\u043E\u043B\u0436\u043D\u0430 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u043A\u0430\u043A \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0434\u0430\u044E\u0449\u0435\u0435 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442 \u0440\u0430\u0431\u0441\u0442\u0432\u043E \u0438 \u0437\u0430\u043F\u0435\u0447\u0430\u0442\u044B\u0432\u0430\u0435\u0442, \u0442.\u0435. \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0443\u043C \u0441\u043B\u0438\u0442\u044C\u0441\u044F \u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F. \u0418\u0442\u0430\u043A, Khecar\u012B mudr\u0101 \u2014 \u044D\u0442\u043E \u043C\u0443\u0434\u0440\u0430, \u0438\u043B\u0438 \u0431\u043B\u0430\u0436\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F \u0432 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, Khecar\u012B mudr\u0101 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u015Aiva, \u043D\u0430 \u0447\u0442\u043E \u0438 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u0434\u043D\u0438\u043C \u0438\u0437 \u044D\u043F\u0438\u0442\u0435\u0442\u043E\u0432 \u015Aiva \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Khecara, \u0442\u0435\u0440\u043C\u0438\u043D Khecar\u012B mudr\u0101 \u044F\u0441\u043D\u043E \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u0415\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435.</p></li><li><p>\u0421\u043B\u043E\u0432\u043E &quot;Ati\u015B\u0101nta&quot; \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u043E \u0434\u0432\u0443\u043C\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438. \u041F\u0435\u0440\u0432\u044B\u0439, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044F \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 &quot;\u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E&quot;\u0434\u043B\u044F \u043F\u0440\u0435\u0444\u0438\u043A\u0441\u0430 &quot;\xE1ti&quot;, \u044D\u0442\u043E\u0442 \u0442\u0435\u0440\u043C\u0438\u043D \u043C\u043E\u0436\u0435\u0442 \u043E\u0437\u043D\u0430\u0447\u0430\u0442\u044C &quot;\u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E \u015B\u0101nta, \u0438\u043B\u0438 \u043C\u0438\u0440\u043D\u044B\u0439&quot;. \u0412\u0442\u043E\u0440\u043E\u0439, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044F \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 &quot;\u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438, \u0432\u043D\u0435&quot;, \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u043E\u0437\u043D\u0430\u0447\u0430\u0442\u044C &quot;\u0432\u043D\u0435 \u015B\u0101nta, \u0438\u043B\u0438 \u0442\u043E, \u0447\u0442\u043E \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u043E (\u0442.\u0435. \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u043E)&quot;. \u0412 \u044D\u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 Ati\u015B\u0101nta, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E\u0435 \u0432\u0435\u043B\u0438\u043A\u0438\u043C Yog\u012B, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u044D\u0442\u0438 \u0434\u0432\u0430 (\u0441\u0435\u043C\u044F --Aham, \u0438\u043B\u0438 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435--\u0438 Khecar\u012B) \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0442\u0441\u044F, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E \u0421\u043F\u0430\u043D\u0434\u043E\u0439 (Spanda), \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u0435\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438. \u0421\u043F\u0430\u043D\u0434\u0430 \u0435\u0441\u0442\u044C \u015Aakti, \u0442.\u0435. \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u043F\u043E\u043A\u043E\u0435, \u0430 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li></ol></div>',1),p=[i];function s(o,h,u,n,c,k){return m(),e("div",null,p)}var y=a(r,[["render",s]]);export{v as __pageData,y as default};
